class Solution {
    public int rob(int[] nums) {
        return dp(nums, 0);
    }

    private int dp(int[] nums, int index) {
        if (index >= nums.length) return 0;
        // Rob this house, skip next
        int rob = nums[index] + dp(nums, index + 2);
        // Skip this house
        int skip = dp(nums, index + 1);
        return Math.max(rob, skip);
    }
}

class Solution {
    public int rob(int[] nums) {
        int[] memo = new int[nums.length];
        Arrays.fill(memo, -1);
        return dp(nums, 0, memo);
    }

    private int dp(int[] nums, int index, int[] memo) {
        if (index >= nums.length) return 0;
        if (memo[index] != -1) return memo[index];
        int rob = nums[index] + dp(nums, index + 2, memo);
        int skip = dp(nums, index + 1, memo);
        return memo[index] = Math.max(rob, skip);
    }
}

class Solution {
    public int rob(int[] nums) {
        int prev = 0, curr = 0;
        for (int num : nums) {
            int next = Math.max(curr, prev + num);
            prev = curr;
            curr = next;
        }
        return curr;
    }
}
